// lib/validations/email.ts

export interface EmailValidationResult {
  valid: boolean;
  error?: string;
  normalized?: string;
}

export function validateEmail(email: unknown): EmailValidationResult {
  // Handle non-string inputs
  if (email === null || email === undefined) {
    return { valid: false, error: 'Email is required' };
  }

  if (typeof email !== 'string') {
    return { valid: false, error: 'Email must be a string' };
  }

  const trimmed = email.trim().toLowerCase();

  if (trimmed.length === 0) {
    return { valid: false, error: 'Email cannot be empty' };
  }

  if (trimmed.length > 254) {
    return { valid: false, error: 'Email is too long' };
  }

  // RFC 5322 simplified regex
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  if (!emailRegex.test(trimmed)) {
    return { valid: false, error: 'Invalid email format' };
  }

  // Check for common disposable email domains
  const disposableDomains = ['tempmail.com', 'throwaway.com'];
  const domain = trimmed.split('@')[1];

  if (disposableDomains.includes(domain)) {
    return { valid: false, error: 'Disposable email addresses not allowed' };
  }

  return { valid: true, normalized: trimmed };
}
```

